args.sparql:
SELECT ?eventLabel ?winnerLabel
WHERE {
  wd:Q9668 wdt:P3443 ?event .
  ?event wdt:P641 wd:Q193401 ;
         wdt:P2503 wd:Q6581072 ;
         p:P1344 ?statement .
  ?statement ps:P1344 ?winner ;
             pq:P1346 wd:Q19717 .
  ?event rdfs:label ?eventLabel .
  ?winner rdfs:label ?winnerLabel .
  FILTER (LANG(?eventLabel) = 'en' && LANG(?winnerLabel) = 'en')
}
ORDER BY ?eventLabel

SELECT DISTINCT ?eventLabel ?winnerLabel
WHERE {
  ?event wdt:P361 wd:Q9668 ;
         wdt:P641 wd:Q193401 ;
         p:P1344 ?statement .
  ?statement ps:P1344 ?winner .
  ?event rdfs:label ?eventLabel .
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANG(?eventLabel) = 'en' && LANG(?winnerLabel) = 'en')
  FILTER(CONTAINS(?eventLabel, 'biathlon'))
}
ORDER BY ?eventLabel
